import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.nio.file.Paths;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String baseDirectory = "/path/to/files/";
        String fileName = args[0]; // User input for file name

        try {
            File file = new File(Paths.get(baseDirectory, fileName).toString());
            if (!file.getCanonicalPath().startsWith(new File(baseDirectory).getCanonicalPath())) {
                throw new SecurityException("Invalid file path");
            }

            FileInputStream fis = new FileInputStream(file);
            // Read file content and do something with it
            fis.close();
        } catch (IOException e) {
            System.out.println("Error accessing file: " + e.getMessage());
        } catch (SecurityException e) {
            System.out.println("Security exception: " + e.getMessage());
        }
    }
}

